import { getPitchRange } from "../appData.js";

export const level5 = {
  num: 5, name: "Ear Training & Harmony", focus: "Intervals, chord tones, hearing changes, melodic dictation",
  duration: "48 min",
  setup: "Guitar for chord references. Quiet room. Pitch Detector on.",
  subtitle: "Hearing the Music Inside the Music",
  description: "Your ear is the most important instrument you own. When you hear chord tones inside a chord, you are hearing with your BODY — the root grounds you in the chest, the third colors the throat, the fifth opens the mask. Harmonic hearing is somatic, not just auditory. Dissonant intervals recruit more somatosensory cortex than consonant ones (PMC5608010) — your body literally feels harmony, not just hears it. These exercises train you to hear chord tones, sing intervals, track harmonic changes, and build melodies from what you hear -- not what you've memorized. The hear-feel-choose cycle deepens here: hear the chord, feel which tones pull at your body, choose which one to voice, produce it, compare. Jeff Buckley and Nick Drake could hear music inside chords that other people missed.",
  artists: "Jeff Buckley, Nick Drake",
  unlocks: "The Pentatonic Sandbox (Level 6)",
  review: { label: "Level 3 Check-In", time: 5, exercises: ["v3e2", "v3e5"], prompt: "Sing Do-Re-Mi-Fa-Sol with solfege — check pitch accuracy (v3e2). Then try pentatonic solfege over a drone (v3e5). If intervals feel shaky, revisit Level 3." },
  exercises: [
    {
      id: "v5e0", time: 4, title: "Ear Training Diagnostic: What Do You Hear?", type: "vocal",
      what: "A self-assessment to map your current ear-voice connection. You'll sing chord tones, match intervals, and try to hear harmonic changes — all without checking against a reference until after you've committed to your answer. This reveals where your ear is strong and where it needs training.",
      setup: "Guitar in hand. No capo. Quiet room. Pitch Detector on. Phone recorder ready.",
      recorder: true,
      pitchContour: true,
      referencePitches: getPitchRange("A2", "E4"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      steps: [
        { text: "Strum a C major chord. Let it ring for 3 seconds. Without plucking individual strings, sing the note you hear most prominently. Check with the Pitch Detector — what note did you land on? Was it the root (C), the third (E), or the fifth (G)?", why: "Your ear naturally gravitates toward certain chord tones based on your listening history and vocal range. Most people hear the root or the fifth most prominently. Knowing which chord tone your ear defaults to tells you about your harmonic hearing style — root-hearers tend to track bass lines easily, while fifth-hearers often have a natural sense of harmonic space." },
        { text: "Strum Am. Sing what you hear. Then strum G. Sing what you hear. Then D. Sing what you hear. Don't analyze — just commit to the first note that comes to you for each chord.", why: "Speed matters here. The first note your voice reaches for is coming from your auditory cortex's automatic processing — it's the note your ear-voice connection finds without thinking. The second note you'd reach for is already being filtered through conscious analysis. We want the automatic response because that reveals the true state of your ear training." },
        { text: "Now test intervals. Play the open A string (A2). Sing what you think is a perfect 5th above it (should be E3). Check with the Pitch Detector. Were you sharp, flat, or dead on?", why: "The perfect 5th is the most natural interval in music — it appears in overtones and is easy for most ears to find. If your 5th is accurate, your ear has good foundational interval sense. If it's consistently sharp or flat, that tells you your ear-voice calibration needs adjustment — which is exactly what this level will train." },
        { text: "Play the open A string again. Sing what you think is a major 3rd above it (should be C#3). Check. Then try a minor 3rd (should be C3). Can you hear and produce the difference between major and minor 3rd?", why: "The major/minor 3rd distinction is the emotional fork in the road of Western harmony — major is bright, minor is dark. If you can hear and sing both accurately, your harmonic ear is already well-developed. If they blur together, that's the primary skill this level will build. Research on auditory categorization shows that the brain learns to separate similar sounds through repeated exposure and feedback — exactly what these exercises provide." },
        { text: "Strum a chord progression: Am - C - G - D. Sing the root of each chord as it changes. Can you track the root movement by ear, or do you need to think about what chord comes next?", why: "Tracking root movement through a chord progression is the fundamental ear training skill for singers. If you can hear the root change and sing it in real time, your harmonic awareness is solid. If you have to think about what chord comes next (relying on memory rather than hearing), your ear needs more training in real-time harmonic tracking — which exercises v5e1 through v5e5 will develop." },
        { text: "Final test: strum Am and sing any 3-note melody using only chord tones (A, C, E). Then strum C and create a new 3-note melody from its chord tones (C, E, G). Can you build melodies on the fly from what you hear in the chord?", why: "Melodic improvisation from chord tones is the endpoint skill of ear training — it combines hearing chord tones, singing accurate intervals, and making musical choices in real time. If this feels natural, you're ready for the advanced exercises in this level. If it feels like guesswork, the earlier exercises will build the ear-voice foundation you need." },
        { text: "Rate yourself honestly: chord tone hearing (1-5), interval accuracy (1-5), root tracking (1-5), melodic improvisation (1-5). Write these down. You'll repeat this diagnostic at the end of Level 5 to measure progress.", why: "Self-assessment creates accountability and reveals growth. Many ear training improvements happen gradually and feel invisible from the inside — you don't notice that your intervals have gotten more accurate because the improvement happens incrementally. Comparing your beginning and end scores gives you concrete evidence of progress that keeps motivation high." }
      ],
      feel: "This should feel like exploration, not examination. There are no failing scores — every result tells you something useful about where to focus your practice. Your ear is already doing amazing things; this diagnostic just maps what it does well and what it needs help with. Before you begin, ask yourself: what ONE aspect of your ear are you most curious about? Hold that question through the exercise.",
      wrong: "If you're guessing instead of hearing, slow down. The difference between hearing and guessing is crucial: hearing means the note feels right in your body before you sing it; guessing means you're doing mental math to figure out what the note should be. If everything feels like guessing, spend more time just listening to chords ring out before trying to sing anything.",
      sarah: "Gene, your guitar playing means your hands already know these intervals — your fingers find them automatically on the fretboard. This diagnostic is about building the same automatic connection between your ear and your voice. The knowledge is already in your body; we're just wiring it to your voice.",
      levelUp: "Complete the full diagnostic with honest self-ratings. Use the results to prioritize exercises in this level."
    },
    {
      id: "v5e1", time: 4, title: "Chord Tone Singing", type: "vocal",
      what: "Strum a chord on guitar and sing the notes you hear — without plucking individual strings first. Trust your ear to find the notes hidden in the harmony. The chord is a house; the chord tones are the rooms inside it. Learn to walk through the rooms by ear.",
      setup: "Guitar in hand. Strum C chord. Let it ring. Pitch Detector on.",
      referencePitches: getPitchRange("C3", "C4"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      pitchContour: true,
      steps: [
        { text: "Strum C chord once, full and open. Let it ring for 5 seconds. Close your eyes. Feel the chord in your body — not just in your ears, but in your chest, your jaw, your skull. Which note pulls at you physically? Without thinking, sing the first note you hear. Hold it. Notice where the vibration settles in your body as you sing it — the root tends to ground in the chest, the third warms the throat, the fifth opens the mask. Before checking, predict: were you on the root, the third, or the fifth? Commit to your answer, THEN check the Pitch Detector. Training your self-assessment is as important as training your pitch.", why: "Your ear naturally gravitates to chord tones. The auditory cortex performs a kind of unconscious spectral analysis of the chord, separating the individual frequencies even when your conscious mind hears a single sound. The note you sing first is the one your brain identified most strongly — usually the root (C) or the fifth (G), because these are the strongest overtones." },
        { text: "Keep the chord ringing (re-strum if needed). Now find a DIFFERENT note in the chord. Sing it and hold it — notice how the vibration lives in a different place in your body. The root (C) grounds you in the chest. The third (E) brightens the throat. The fifth (G) opens the space behind your nose. Check. Then a third note. You should be able to find C, E, and G — the three notes hiding in the C chord, each with its own body address.", why: "Each chord contains at least three distinct pitches, blended together. Training your ear to separate them is like training your eyes to see the individual colors in a rainbow — they're all there; you just need to learn to isolate them. Some people hear the root easily but struggle with the third. Others find the fifth immediately but can't isolate the third. Everyone has a different hearing profile." },
        { text: "Sing 3-4 notes you hear in the chord, one at a time, going from lowest to highest. Commit to each one even if it feels wrong. Then re-strum and check: do they all belong to the chord? Even the unexpected ones?", why: "Even 'wrong' notes can be beautiful in context. Sarah once noticed Gene singing F# over a C chord — technically a tritone, theoretically dissonant — but it worked because of the harmonic context and his delivery. The point isn't to always find the 'right' notes; it's to trust your ear and discover what it finds. Sometimes the most interesting music comes from notes your ear finds that your theory brain would reject." },
        { text: "Now strum Am. Let it ring. Find the notes: A, C, E. Compare to C major — they share two notes (C and E) but the root changes everything. Notice how the same C note feels different over Am than over C major.", why: "Shared tones between chords are the connective tissue of harmony. C and E appear in both C major and A minor, but they sound and feel different because the root changes the harmonic context. This is called 'recontextualization' — the same pitch carries different emotional weight depending on which chord it lives over. Training your ear to feel this difference is fundamental to harmonic listening." },
        { text: "Strum G major. Find the notes: G, B, D. The B is the tricky one — it's a major third, bright and ringing. Compare to the minor third (C) you found in Am. Can you feel the emotional difference between major and minor thirds when you sing them?", why: "The major third (B in G chord) and minor third (C in Am chord) are only one half-step apart, but they define completely different emotional worlds. Major third = brightness, resolution, happiness. Minor third = depth, longing, mystery. Your ear needs to feel this difference viscerally, not just intellectually. When you can sing both and feel the emotional shift, your harmonic hearing has reached a meaningful level of sophistication." },
        { text: "Strum D major. Find D, F#, A. The F# is interesting — it's the same note Gene accidentally sang over C that Sarah loved. Notice how it feels consonant and stable over D but would feel tense over C. Same note, different context.", why: "This exercise demonstrates that 'wrong' and 'right' in music are always relative to context. F# is the major third of D (perfectly consonant) and the tritone of C (maximally dissonant). Your ear needs to understand that notes aren't inherently good or bad — they're good or bad in relation to the chord they're over. This relational hearing is what separates musicians who improvise well from those who play scales over chords." },
        { text: "Cycle through all four chords (C-Am-G-D), spending one bar on each. On each chord, sing the chord tone that is most different from the previous chord's tone. This forces your ear to track what changes.", why: "Tracking changes between chords — what stays the same and what moves — is the essence of harmonic listening. When you focus on what changes, you're training the predictive processing system in your auditory cortex. Your brain learns to anticipate harmonic motion, which is the foundation of melodic improvisation. Jeff Buckley's otherworldly melodic sense came from an extraordinary ability to hear what changes between chords." },
        { text: "Record yourself finding chord tones across all four chords. Listen back. Were the notes you sang actually chord tones? Any happy accidents (notes that weren't chord tones but sounded great)?", why: "The recording provides objective feedback that calibrates your ear-voice connection. Sometimes you'll be convinced you sang the right note but the recording reveals you were a half-step off. Other times, you'll sing what feels like a mistake but sounds beautiful on playback. Both experiences are valuable — they refine the internal model your brain uses to connect what you hear to what you sing." }
      ],
      feel: "This should feel exploratory, not like a test. There are no wrong answers — your ear is finding musical connections your conscious mind doesn't know about yet. Each chord is a garden; you're learning to see the individual flowers. Notice where each chord tone resonates in your body: the root often feels grounding, settling into your chest. The third colors the sound with warmth or brightness somewhere around the throat and jaw. The fifth feels open, spacious, reaching toward the mask. Your body responds to harmony before your mind names it.",
      wrong: "If you're plucking individual strings to find the notes first, you're bypassing your ear. The whole point is to let your singing brain find them. If you truly can't hear any notes in the chord, hum very quietly while the chord rings — the hum will naturally gravitate to a chord tone, and you can amplify from there.",
      sarah: "It is actually a great thing when you find unexpected notes, because that means your ear is hearing overtones and harmonic relationships that go beyond basic theory. Trust what you hear, even when it surprises you. Before each chord, let it ring for a few seconds and feel the groove settle into your body — your ear opens wider when your body is entrained to the harmonic field.",
      levelUp: "Can find 3+ notes per chord that sound musical, across all 4 chords, without plucking reference strings."
    },
    {
      id: "v5e2", time: 4, title: "Interval Recognition & Production", type: "vocal",
      what: "Sing specific intervals over Am: root, minor 3rd, 5th, octave. Then track chord tones through Am->C->G->D. This trains your ear to hear, name, and produce specific intervals — the building blocks of all melody and harmony.",
      setup: "Guitar: Am chord. Slow strum. Pitch Detector on.",
      referencePitches: getPitchRange("A2", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      pitchContour: true,
      steps: [
        { text: "Strum Am. Sing the root (A). Hold it until it feels perfectly stable — no wavering. Then sing up to the minor 3rd (C). Feel the interval. The distance between A and C should feel like a small, dark step upward.", why: "The minor 3rd is the sound of depth, longing, and beauty. It's the interval that defines minor chords — the emotional color of Nick Drake, Elliott Smith, and much of the psych-folk Gene loves. Learning to hear it as a specific sound (not just 'some notes') is ear training 101. Think of the first two notes of 'Greensleeves' — that's a minor 3rd leap. Once you associate the interval with a song you know, your ear can find it anywhere." },
        { text: "From the root (A), sing up to the 5th (E). Hold it. Then the octave (A, one octave up). These four notes — root, minor 3rd, 5th, octave — are the skeleton of the Am chord. Sing them as an ascending arpeggio: A-C-E-A.", why: "Root, 3rd, 5th, and octave are the four most important intervals in music. They're the skeleton of every chord — everything else is decoration. When you can sing these four intervals accurately from any starting note, you can outline any chord with your voice. This is how jazz singers navigate complex harmony and how folk singers create melodies that fit perfectly over guitar chords." },
        { text: "Now reverse: sing the descending arpeggio A(high)-E-C-A(low). Descending intervals feel different from ascending ones — the same distance traveled downward has a different emotional quality.", why: "Descending intervals carry different emotional weight than ascending ones. An ascending minor 3rd feels like reaching up into sadness; a descending minor 3rd feels like settling into it. Your auditory cortex processes ascending and descending intervals through partially different neural pathways, which is why you can be good at ascending intervals and shaky at descending ones (or vice versa). Train both directions." },
        { text: "Change to the Am->C->G->D progression. On each chord, sing just the root: A, C, G, D. One root per bar, landing on beat 1. Track the roots through the changes.", why: "Tracking roots through changes is the simplest form of following harmony. Your voice maps the bass line — the harmonic foundation of the music. If you can sing the root of each chord as it changes, you're demonstrating real-time harmonic awareness. This is the skill that lets singers stay in tune over changing harmony, rather than singing a fixed melody regardless of the chords underneath." },
        { text: "Same progression, but sing the 3rd of each chord: C over Am, E over C, B over G, F# over D. These are harder to find because the 3rd changes quality (minor or major) with each chord.", why: "Singing 3rds requires hearing the chord quality (major vs minor) and finding the right note. The 3rd is the note that defines whether a chord sounds happy (major) or sad (minor). When you track 3rds through a progression, you're hearing the emotional arc of the harmony — Am (minor 3rd C, dark) to C (major 3rd E, bright) to G (major 3rd B, bright) to D (major 3rd F#, bright). That minor-to-major shift is the emotional engine of this progression." },
        { text: "Now sing the 5th of each chord: E over Am, G over C, D over G, A over D. Notice how some 5ths are shared between adjacent chords (E appears as the 5th of Am and the 3rd of C).", why: "Tracking 5ths reveals the harmonic overlaps between chords — the shared tones that create smooth voice leading. When you notice that E is the 5th of Am AND the 3rd of C, you're hearing how chords connect to each other. This connective hearing is what allows great melodists like Nick Drake to write melodies that seem to flow effortlessly from one chord to the next — they're following the shared tones." },
        { text: "Challenge round: sing root of Am, 3rd of C, 5th of G, root of D. Mix different chord tones across the progression. This requires hearing each chord's identity AND choosing a specific tone from it.", why: "Mixing chord tones across a progression is real-time melodic decision-making. You're hearing the chord, choosing a specific tone from it, and singing it accurately — all in the time it takes for one bar to pass. This is the cognitive foundation of melodic improvisation. When this feels natural, you'll be able to create melodies on the fly that perfectly fit the harmony." },
        { text: "Record yourself singing through the progression with mixed chord tones. Listen back. Did you nail the intervals? Were you consistently sharp or flat on any particular interval? Use the Pitch Detector data to identify patterns in your accuracy.", why: "Interval accuracy patterns reveal your ear's strengths and blind spots. Many singers consistently sing minor 3rds slightly sharp (pulling toward the major 3rd) or 5ths slightly flat. These consistent errors aren't random — they reflect biases in how your auditory cortex categorizes intervals. Identifying the pattern lets you practice targeted corrections." }
      ],
      feel: "The root should feel stable, grounded — like standing on solid earth, vibration sitting heavy in the chest. The 3rd defines the chord's emotion (minor = deep blue, pulling inward; major = sunlit, opening outward) — notice how your throat and jaw configure differently for each. The 5th is open and powerful — like a wide sky, the vibration spreading into the mask. The octave is home, elevated — the same note reborn higher in the body. Each interval has a body address as much as a sound.",
      wrong: "If the 3rds all sound the same to you, slow down dramatically. Strum each chord, pluck the 3rd string, sing it, feel it. Then try without plucking. The major/minor distinction is the single most important ear training skill — don't skip past it.",
      sarah: "Gene, your guitar gives you a huge advantage here — your fingers already know where these intervals are on the fretboard. We're just training your voice to find the same notes your hands already know. Think of it as building a bridge between your guitar brain and your singing brain.",
      levelUp: "Sing root and 3rd of each chord through Am-C-G-D without plucking reference notes, with consistent accuracy confirmed by Pitch Detector."
    },
    {
      id: "v5e3", time: 4, title: "Melody From Chord Tones", type: "vocal",
      what: "Build simple melodies using only chord tones. This is the Jack Johnson / Nick Drake approach — melodies that live inside the chords, never fighting the harmony. Every note belongs. Every note has a home.",
      setup: "Guitar: Am -> C -> G -> D. Slow fingerpick at about 70 BPM.",
      referencePitches: getPitchRange("A2", "B3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      steps: [
        { text: "On Am, sing any two chord tones (A, C, or E) in any order. Feel each note arrive in its body address — A grounds in the low chest, C warms the throat, E opens the mask. That is your Am melody fragment. Keep it simple — just two notes. Hold the second note until the chord changes. The melody is a journey between body locations as much as between pitches.", why: "Limiting yourself to chord tones guarantees consonance. Every note will 'work' against the chord. This constraint might feel limiting, but it's actually liberating — you can't make a 'wrong' choice, so you're free to focus on rhythm and phrasing instead of worrying about pitch accuracy. Nick Drake's melodies are almost entirely chord tones, and they're some of the most beautiful in folk music." },
        { text: "On C, sing two different chord tones (C, E, or G). Choose tones that connect smoothly to your Am notes — if you ended Am on E, start C on E (same note, new chord) or G (step up).", why: "The connection between chords is where melody lives. Smooth voice leading — moving by small intervals or staying on shared tones — creates beautiful, flowing melodies. This is the secret of great melodists: they don't jump randomly from chord tone to chord tone. They find the smoothest path between harmonic islands. When you connect Am's E to C's E, you're holding one note while the harmony moves underneath — a powerful melodic technique called a 'common tone.'" },
        { text: "Continue through G and D. On each chord, choose two chord tones that connect smoothly to the previous chord's notes. Aim for stepwise motion (notes close together) or common tones (same note held over).", why: "Stepwise motion (moving by 2nds) and common tones (holding a note) sound more melodic than big jumps. The human auditory system evolved to track smooth pitch contours — sudden large jumps require more cognitive effort to process, which breaks the melodic flow. When you prioritize stepwise motion, you're working with the brain's natural tendencies rather than against them." },
        { text: "Play the progression 4 times, singing a different 2-note-per-chord melody each time. Each pass, try a different approach: ascending motion, descending motion, a mix, and common tones only.", why: "Multiple passes with different constraints build improvisational flexibility. Each approach creates a different emotional arc: ascending melodies feel hopeful, descending melodies feel settling or melancholic, mixed contours feel conversational, and common tones feel hypnotic. Having all four approaches available means you can choose the emotional color that fits the moment." },
        { text: "Now expand to 3 notes per chord. You can use all three chord tones in any order: ascending arpeggio, descending, or scrambled. Connect across chords as smoothly as possible.", why: "Three notes per chord allows for arpeggiated patterns — the melody can literally outline the chord shape with your voice. This is how Jeff Buckley created his otherworldly vocal lines in songs like 'Grace' — his voice arpeggiated chord extensions, making the melody and the harmony inseparable. Three notes also give you enough material to create rhythmic interest, varying which notes get longer or shorter." },
        { text: "Try adding one non-chord tone per chord as a passing note. For example, on Am (A-C-E), add a B between A and C, creating A-B-C-E. The B is a passing tone that adds melodic movement without disrupting the harmony.", why: "Passing tones are the secret ingredient that turns chord-tone melodies from exercises into music. Chord tones alone sound like arpeggios; adding passing tones between them creates the sense of a real melody in motion. The passing tone creates a brief tension (it doesn't belong to the chord) that immediately resolves to the next chord tone (which does). That tension-resolution cycle is what makes melodies feel alive." },
        { text: "Play the full progression 4 times. Create a complete melody — the same melody all 4 times — using chord tones and passing tones. This should sound like a real song melody, not an exercise.", why: "Repeating the same melody over the same progression is how songs work. The melody becomes familiar and singable. If your melody sounds like it could be a verse in a Jack Johnson or Nick Drake song, you've successfully created music from chord tones. The shift from exercise to music happens when the melody has shape, phrasing, and emotional arc — not just correct pitches." },
        { text: "Record the final version. Play it back while playing guitar. Does it sound like a song? If it does, congratulations — you just wrote a melody. Save the recording.", why: "Melodic creation from chord tones is the most direct path to songwriting. Every melody you create using this method is harmonically sound — it fits the chords by definition. Many great songwriters (Nick Drake, Jack Johnson, Ben Harper) compose exactly this way: they play chords and let their voice find the melody within the harmony. You're learning the same process." }
      ],
      feel: "Every note should feel like it belongs — not just sonically, but physically. When the melody follows chord tones, your body relaxes into each note: no tension, no searching, just arrival. This is what makes Jack Johnson's melodies feel so effortless — they're built from chord tones, so they never fight the harmony. The melody floats inside the chords like a bird inside a warm current. As you move between chord tones, notice how the body sensation shifts with the harmonic function: roots settle into the chest, thirds brighten or darken the throat, fifths open the space behind your nose. The melody is a journey through your body as much as through the chords.",
      wrong: "If your melody sounds boring or academic, try adding rhythmic variation — hold some notes longer, make others short. Melodic interest comes from both pitch AND rhythm. A boring melody on good pitches often just needs better phrasing to come alive.",
      sarah: "This is where Gene's guitar knowledge becomes a superpower. You already know these chords inside out. Now your voice is learning to navigate the same harmonic territory. When your voice and your guitar both know the chord tones, improvisation becomes a conversation between them. Shape these melodies however you want — long phrases, short fragments, rhythmic or floating. The chord tones are the map; how you travel it is entirely yours.",
      levelUp: "Improvise a 4-chord melody that sounds like a real song snippet, using mostly chord tones with occasional passing tones, connected by smooth voice leading."
    },
    {
      id: "v5e4", time: 5, title: "Low Register Stretch & Chest Voice Depth", type: "vocal",
      what: "Extend the chest voice downward: sing descending 5-note scales from A3 down to E3, then D3, then C3. Use 'mah' to keep the throat open. This is range expansion work that builds the warm low tones essential for your porch-register delivery.",
      setup: "Standing. Pitch Detector on. No guitar. Warm up with lip trills first.",
      referencePitches: getPitchRange("C3", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      pitchContour: true,
      volumeMeter: true,
      metronome: 70,
      recorder: true,
      steps: [
        { text: "Warm up: do 1 minute of lip trills, starting at A3 and descending as low as they'll go. The trills should buzz evenly — if they sputter, you're using too much air pressure.", why: "Lip trills are the safest warm-up for low range work because they automatically regulate air pressure. The buzzing lips create a back-pressure that prevents you from pushing too hard, which is especially important when reaching for low notes where the vocal folds are thick and loose. Starting at A3 and descending gradually wakes up the low range without shocking it." },
        { text: "Start on A3. Before you descend, hear the full path internally: A3 at the throat, G3 settling into the upper chest, F3-E3 deepening into the mid-chest, D3 arriving behind the sternum. Then sing a descending 5-note scale: A3-G3-F3-E3-D3 on 'mah'. One note per beat at 70 BPM. Feel each note as a deeper layer of chest resonance — the vibration grows heavier and warmer with each step down. Keep each 'mah' full and resonant — no trailing off at the bottom.", why: "Starting at A3 keeps you in comfortable territory. 'Mah' opens the throat because the 'M' engages the lips (creating forward resonance) and the 'ah' drops the jaw (creating space). The combination naturally positions the vocal tract for optimal low-range resonance. Descending scales are better than ascending ones for low range work because you're easing into the lower notes from a position of strength." },
        { text: "Next round: start on G3. Descend G3-F3-E3-D3-C3. The lower notes should feel warm and rumbly, like your voice is settling into your chest cavity. Keep the 'mah' vowel open.", why: "Each round pushes the bottom of your range a little further. C3 is the target floor for a tenor — it's where the chest voice reaches its richest, warmest tone. Below C3, most tenor voices lose resonance and projection. The 'warm and rumbly' sensation comes from the chest cavity resonating sympathetically with the low frequencies — you should literally feel vibration in your sternum." },
        { text: "Try one more: F3-E3-D3-C3-B2. If B2 doesn't come cleanly, stop at C3 — that's your current floor, and that's fine. B2 is the frontier, not the requirement.", why: "Below C3, many tenors lose projection and tonal quality. Knowing your real floor is more useful than forcing notes that aren't there yet. Vocal range extends gradually over weeks and months of consistent practice, not in a single session. If B2 comes cleanly today, great. If not, it might come next week or next month. The voice is a physical instrument with physical limitations that respond to gradual training." },
        { text: "On each scale, keep the volume steady — don't get quieter as you go lower. Use the Volume Meter to monitor. The breath support should come from the ribs expanding, not from pushing more air.", why: "The tendency is to lose volume on low notes because the vocal folds vibrate with less amplitude at lower pitches. Rib expansion breathing from Level 1 keeps the airflow consistent by maintaining subglottic pressure (the air pressure beneath the vocal folds). Think of the ribs as bellows — they maintain steady pressure while the vocal folds handle the pitch. If the Volume Meter shows a dip on the low notes, focus on keeping the ribs expanded." },
        { text: "Rest for 30 seconds. Then sing a sustained C3 for as long as you can on 'mah'. Time it. The note should be steady — no wavering pitch, no wobbling volume. This is your low-range endurance test.", why: "Sustained low notes test both breath support and vocal fold closure. The vocal folds are thicker at low pitches and require more precise coordination to maintain a steady vibration. If the note wobbles, the folds are losing their closure pattern. If the volume fades, you're running out of breath support. Both improve with practice. Track your sustained-note time over weeks to see progress." },
        { text: "Sing a descending phrase using words: 'The sun goes down behind the sea' — starting at A3 and ending on or near your lowest comfortable note. The words should sound warm and natural, not strained.", why: "Transferring low-range exercises to actual words is essential because singing involves different vocal tract shapes than 'mah.' Consonants interrupt the airflow, vowels change the resonance, and the combination tests your low-range control in realistic conditions. If the low notes that sounded fine on 'mah' fall apart with words, spend more time on this step — it means the technique isn't fully integrated yet." },
        { text: "Record the full exercise sequence. Listen back with focus on the lowest notes: Are they warm and resonant, or airy and thin? Is the pitch accurate (check Pitch Detector data), or do the low notes go flat? Flat low notes mean you need more breath support, not more effort.", why: "Low notes going flat is the most common error in low-range singing. The natural tendency when reaching for a low pitch is to reduce air support (because loud low notes feel effortful), but reduced support causes the pitch to sag. The counterintuitive solution is to maintain or even increase breath support while reaching lower. It feels like more work, but the pitch accuracy improves dramatically." }
      ],
      feel: "Low notes should feel warm, resonant, and grounded — like your voice is settling into your chest. The 'mah' should vibrate in your sternum. There should be no strain, no squeezing — just a steady, open, rumbling tone that you can feel physically vibrating in your ribcage.",
      wrong: "If the low notes sound airy or disappear, you're letting go of breath support. Keep the ribs expanded. If you're straining or growling to reach a note, it's below your range today — stop one note higher. Never force low notes; the vocal folds respond to gentle, consistent stretching over time, not to brute force.",
      sarah: "Your low range is like a muscle — it extends with gentle, consistent stretching. Never force it. The notes will come over weeks, not minutes. Gene, your 'porch voice' — that warm, low delivery — lives in this register. Building it out gives you more room to be expressive in your natural territory.",
      levelUp: "Clean descending scales reaching C3 with consistent volume and warm tone, 3 rounds, with a sustained C3 held for at least 8 seconds."
    },
    {
      id: "v5e5", time: 4, title: "Sing the Bass Line", type: "vocal",
      what: "Sing the root notes of a progression in rhythm against a backing track. Your voice becomes the bass instrument — low, grounded, rhythmic. This is the first step toward looper bass vocal lines and toward hearing the harmonic foundation of any song.",
      setup: "Guitar: Am -> C -> G -> D. Simple strum at 85 BPM. Or use Dub Reggae 85 backing track.",
      referencePitches: getPitchRange("A2", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      metronome: 85,
      recorder: true,
      tracks: [{ name: "Dub Reggae 85", src: "/dub-reggae-85.mp3" }, { name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }],
      steps: [
        { text: "Start with guitar or backing track at 85 BPM. Sing the root of each chord on beat 1: A (low), C, G, D. One note per bar, landing precisely on beat 1. Hold each note for 2 beats, then silence for beats 3-4.", why: "Root notes in rhythm = bass line. Your voice is doing what a bass player does — providing the harmonic foundation. Singing roots on beat 1 anchors the progression in the most fundamental way possible. The 2-beat sustain gives the note presence, while the silence on beats 3-4 leaves space for the chord to breathe. This is the simplest bass pattern and the most common in reggae." },
        { text: "Add a second note: sing the root on beat 1, the 5th on beat 3. A-E (Am bar), C-G (C bar), G-D (G bar), D-A (D bar). Now you have a two-note bass line per bar.", why: "Root-5th patterns are classic bass lines across virtually every genre. The 5th reinforces the root's harmonic identity — it's the strongest consonance in music (after the octave). From reggae to country to rock, root-5th bass patterns are the backbone of rhythm sections. When you sing root-5th, you're reproducing the most universal bass pattern in Western music." },
        { text: "Try a walking pattern: root on beat 1, then step up by chord tone to beat 3: A-C-E (Am), C-E-G (C), G-B-D (G), D-F#-A (D). Three ascending chord tones per bar.", why: "Walking bass lines create melodic movement within the harmonic structure. Instead of jumping between roots, the bass 'walks' through the chord tones, creating a sense of forward motion. This is common in jazz, soul, and some reggae bass lines. Singing walking patterns trains your ear to hear the internal structure of each chord as a series of available melodic steps, not just a single root note." },
        { text: "Sing the bass line in your low register. Use chest voice, project from the belly. The notes should feel heavy and grounded — like your voice is the lowest instrument in the room.", why: "Bass lines live in the low range, ideally in your chest voice sweet spot (E3-A3 for Gene). This is where your Level 1 chest voice training and the low register stretch from v5e4 pay off. Low singing with good projection requires strong breath support — the ribs stay expanded, the diaphragm stays engaged, and the voice resonates in the chest cavity rather than floating in the head." },
        { text: "Switch to the Deep Soul Groove 80 backing track. Sing root-5th bass lines against it. Notice how the bass in the track is doing exactly what you're singing — you're doubling the bass player. Feel how your voice locks in with the rhythm section.", why: "Singing along with an existing bass line trains your ear to hear what bass players actually do. The Deep Soul Groove track has a prominent bass that follows root-5th patterns. When your voice and the bass in the track sync up, you'll feel a physical resonance — a 'locking in' sensation that tells you you're hearing the harmonic foundation accurately." },
        { text: "Now try the hardest version: listen to the backing track and figure out the bass line by ear. Don't think about chord names — just listen to the lowest notes and sing what you hear. Check your accuracy against the Pitch Detector.", why: "Ear-based bass line transcription is a core aural skill. When you can hear what the bass is doing in any recording, you can understand the harmonic structure of any song. This skill transfers directly to learning songs by ear, which is how Jeff Buckley, Nick Drake, and most of Gene's musical heroes learned music." },
        { text: "Record your best bass line attempt over either backing track. Play it back while you play guitar over the same track. How does the combination sound? This is a preview of Level 7's looper work — your voice as bass, your guitar as melody.", why: "Preview of Level 7: you'll eventually loop bass vocal lines and play guitar over them. Hearing your recorded voice and live guitar together gives you a taste of that layered sound. If the bass vocal line sounds solid against your guitar playing, you're developing the multi-instrument awareness that looper performance requires." }
      ],
      feel: "Your voice should feel low, grounded, rhythmic — like a bass guitar. The notes should anchor the harmony, not float above it. There's a physical weight to bass vocal singing — you should feel the vibration in your chest and belly.",
      wrong: "If you can't reach the low notes comfortably, transpose up an octave. The pattern matters more than the range at this stage. An octave-up bass line still teaches you root movement, harmonic tracking, and rhythmic bass patterns — the pitch register is secondary to the functional understanding.",
      sarah: "Gene, this exercise is where your guitar knowledge and your vocal training start to merge. You already know what bass players do — now your voice is learning to do it. When you eventually get to the looper exercises, this bass vocal skill will be the foundation of everything.",
      levelUp: "Clean bass vocal line through Am-C-G-D with root-5th pattern at 85 BPM, with consistent low register projection and accurate pitch."
    },
    {
      id: "v5e6", time: 4, title: "Relative Pitch Games", type: "vocal",
      what: "Play a note on guitar, then sing a specific interval above or below it. Ear-voice connection training — you hear the target in your head, then your voice finds it. This is the bridge between knowing intervals intellectually and producing them instantly.",
      setup: "Guitar in hand. Random notes across the neck. Pitch Detector on.",
      referencePitches: getPitchRange("A2", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      pitchContour: true,
      steps: [
        { text: "Play any note on guitar. As the note enters your ears, close your eyes and hear it continue internally for 2 seconds after the string stops ringing. Feel where in your body that pitch would live — E3 sits deep in the mid-chest, G3 warms the upper chest, A3 hovers at the throat (the passaggio transition zone), B3 reaches toward the jaw, C4 buzzes in the lower mask. Then sing the same note back on 'lah,' reaching for that body location as much as for the pitch. The body address guides you to the note. This is unison — the simplest interval. Do 10 random notes. Before checking, predict: sharp, flat, or on? Commit to your answer, THEN check the Pitch Detector. Training your self-assessment is as important as training your pitch. How many can you match exactly?", why: "Matching pitch (unison) is the foundation of all relative pitch skills. If you can hear a note and reproduce it with your voice, the ear-voice connection is functioning. Most people can match pitch reasonably well, but the Pitch Detector reveals whether you're consistently a few cents sharp or flat — subtle calibration errors that are invisible to the untrained ear but affect everything else you sing." },
        { text: "Play a note. Sing a major 3rd above it (4 half steps up). Check by plucking 4 frets up on the same string. The major 3rd is happy, bright — think the first two notes of 'Kumbaya' or 'When the Saints Go Marching In.'", why: "The major 3rd is one of the most common intervals in melody. Song associations ('Kumbaya,' 'When the Saints') give your brain a shortcut — instead of calculating 'four half steps,' you hear the song reference and match the interval by feel. Over time, the shortcut fades and the interval itself becomes the reference. This is how professional musicians hear intervals — not through calculation but through internalized sound." },
        { text: "Play a note. Sing a perfect 5th above it (7 half steps). Check by plucking 7 frets up. The 5th is open, powerful, stable — think the opening of 'Twinkle Twinkle Little Star' or the Star Wars theme.", why: "The perfect 5th is the most acoustically pure interval after the octave — it's the first overtone in the harmonic series. It appears in power chords, open tunings, and is the foundation of harmony in nearly every musical tradition worldwide. Your ear is naturally predisposed to hear it because of its prominence in the overtone series. Learning to produce it on command connects your voice to one of the deepest structures in music." },
        { text: "Play a note. Sing a minor 3rd above it (3 half steps). Check by plucking 3 frets up. Compare to the major 3rd — the minor 3rd is darker, more wistful. Think the opening of 'Greensleeves' or Beethoven's 5th (da-da-da-DAH).", why: "The difference between major and minor 3rd is the difference between bright and dark, happy and contemplative. It's only one half step — 3 frets versus 4 — but the emotional change is enormous. Your ear needs to feel that difference viscerally, not just intellectually. When you can produce both on command and feel the emotional shift, you've developed a crucial piece of harmonic awareness." },
        { text: "Play a note. Sing a perfect 4th above it (5 half steps). Think 'Here Comes the Bride' or 'Amazing Grace.' Then immediately sing a perfect 5th above the same starting note. Feel the difference between 4th (5 frets) and 5th (7 frets).", why: "The 4th and 5th are often confused because they're both 'open' and 'stable' sounding. But the 4th has a subtle tension — it wants to resolve somewhere — while the 5th is completely stable. Training your ear to distinguish them prevents one of the most common interval-singing errors. The 4th is the inversion of the 5th: if you flip a 5th upside down, you get a 4th. Once you hear this relationship, both intervals become clearer." },
        { text: "Descending intervals: play a note, sing a major 3rd BELOW it (4 half steps down). Then a perfect 5th below. Then a minor 3rd below. Descending intervals feel different from ascending ones — practice them separately.", why: "Descending intervals are processed differently by the auditory cortex than ascending ones. Many singers who can nail ascending intervals struggle with descending ones (or vice versa). The song association technique works here too — a descending minor 3rd is the beginning of 'Hey Jude,' a descending 5th is 'Feelings.' Building descending interval fluency doubles your melodic vocabulary." },
        { text: "Random interval challenge: have someone play a note (or play one with your eyes closed on the guitar), then call out an interval: 'major 3rd up,' 'perfect 5th down,' 'minor 3rd up.' Sing it immediately. Check. Track your accuracy over 10 attempts.", why: "Random interval challenges test your real-time interval production under pressure. When intervals are randomized, you can't predict what's coming, so you have to rely on your internalized sense of each interval's sound rather than muscle memory or calculation. This is the closest exercise to what you'll actually need in musical situations — hearing a note and knowing where to go from it." },
        { text: "Record a full session of 20 random interval attempts. Review the Pitch Detector data. Which intervals are you consistently accurate on? Which ones need more work? Create a practice priority list based on your results.", why: "Systematic tracking of interval accuracy reveals your ear's specific strengths and weaknesses. Most people have 2-3 intervals they nail consistently and 2-3 that give them trouble. Focused practice on the troublesome intervals (rather than practicing everything equally) is more efficient — it's the musical equivalent of studying your weakest subjects more than your strongest. Your practice priority list should guide how you warm up at the start of each session." }
      ],
      feel: "When you nail the interval, it should feel like the note was already in your head — you just had to let it out. There's a satisfying 'click' when the interval locks in. When you miss, you'll feel the dissonance immediately — a slight unease that tells you something's off.",
      wrong: "If you consistently overshoot or undershoot intervals, sing the interval slowly as a glide first (sliding from the starting note to the target), then try to jump directly. The glide trains the distance — your voice learns how far to travel. Gradually make the glide faster until it becomes a clean jump.",
      sarah: "Gene, interval singing is like learning to throw a ball to a specific target. At first you have to think about the distance and aim carefully. With practice, you just see the target and your arm knows what to do. Your voice will develop that same automatic accuracy. After your last round, set the guitar down for 60 seconds. Then sing each interval from memory, no reference. That retrieval under silence is 50-80% more effective than drilling with a reference.",
      levelUp: "Nail 8 out of 10 random interval challenges (major 3rd, minor 3rd, perfect 4th, perfect 5th, up and down) without checking on guitar first."
    },
    {
      id: "v5e7", time: 4, title: "Melodic Dictation: Hear It, Sing It, Know It", type: "vocal",
      what: "Listen to a short melody, hold it in your memory, sing it back, then figure out the intervals. This exercise trains melodic memory — the ability to hear a phrase once and reproduce it, which is the foundation of learning songs by ear.",
      setup: "Guitar in hand (to play melodies for yourself). Pitch Detector on. Quiet room. Recorder ready.",
      referencePitches: getPitchRange("E3", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      pitchContour: true,
      steps: [
        { text: "Play a simple 3-note melody on guitar — any three notes in the E3-A3 range. Listen to it once without singing. Close your eyes. Can you hear the melody replay in your head? Now add the body channel: feel it as a journey through your torso. The first note lives somewhere specific — E3 in the mid-chest, G3 at the upper chest, A3 at the throat. The second note shifts the vibration to a new address. The third arrives at yet another location. The melody is a path through body space as much as pitch space. Hold all three body addresses for 2 seconds. If you can feel the path, sing it back immediately, reaching for each body location in sequence.", why: "Melodic memory — the ability to hold a melody in your mind after hearing it — is called 'auditory imagery' in neuroscience. Your auditory cortex actually reactivates the same neural patterns during recall as during the original hearing. The better your auditory imagery, the more accurately you can sing back what you've heard. Starting with 3 notes keeps the memory load manageable while building the skill." },
        { text: "Play a different 3-note melody. This time, after singing it back, identify the intervals: was the first jump a 2nd? A 3rd? A 5th? Up or down? Name each interval, then verify by counting frets on the guitar.", why: "Naming the intervals adds an analytical layer to the memory task. Instead of just reproducing the melody as a gesture (a holistic motor pattern), you're breaking it down into components (discrete intervals). This dual encoding — gestural AND analytical — strengthens the memory trace and builds the vocabulary you need to communicate musical ideas. It's the difference between imitating a sentence in a foreign language and actually understanding the grammar." },
        { text: "Increase to 4 notes. Play, listen, close eyes, sing back, then analyze the intervals. The extra note significantly increases the memory demand — your brain now has to hold three intervals rather than two.", why: "Each additional note in the melody roughly doubles the memory challenge, because your brain has to track both the individual pitches AND the intervals between them. Research on melodic chunking shows that the brain groups notes into meaningful units (like grouping letters into words), and this chunking ability improves with practice. If 4 notes is too hard, stay at 3 until it's effortless." },
        { text: "Try a 5-note melody: play it once, listen, and sing it back. If you can't remember all 5 notes, which ones do you lose? The first, the last, or the middle? This reveals how your melodic memory organizes information.", why: "Most people remember the first note (primacy effect) and the last note (recency effect) but lose the middle notes. This mirrors how general memory works — it's not specific to music. Knowing your pattern helps you compensate: if you lose middle notes, try to chunk the melody into a beginning fragment and an ending fragment, then connect them." },
        { text: "Now create melodies for yourself: play a 4-note melody on guitar, immediately look away from the fretboard, and sing it back. The act of creating the melody yourself adds a motor-memory component that helps with recall.", why: "When you play a melody yourself, you have three memory channels: auditory (you heard it), motor (your fingers played it), and visual (you saw your hand move). Even though you're testing your auditory recall by looking away, the motor and visual channels provide additional encoding that strengthens the memory trace. This is why musicians learn songs faster when they play along rather than just listening." },
        { text: "Partner exercise (or use a recording): play a 4-note melody, wait 10 seconds in silence, then sing it back. The silence gap tests your working memory — can you hold the melody while nothing else is happening?", why: "The 10-second gap introduces a retention challenge. During silence, auditory memory decays rapidly unless you actively rehearse the melody internally (singing it in your head). This 'inner hearing' skill is what musicians use when they read sheet music silently, compose in their heads, or remember a melody they heard on the radio. Building tolerance for the gap builds the inner-hearing skill." },
        { text: "Challenge round: play a 4-note melody. Before singing it back, play a DIFFERENT 4-note melody. Now sing back the FIRST melody. Can you hold one melody in memory while hearing a different one?", why: "This interference task tests the robustness of your melodic memory. In real musical situations, you're constantly hearing new melodies while trying to remember existing ones (learning a harmony part while hearing the melody, for example). If the second melody erases the first, your melodic memory needs more practice at the basic level before attempting interference tasks. If you can hold both, your auditory working memory is strong." },
        { text: "Record yourself doing the full exercise sequence. Listen back. How accurate were your sing-backs? Did accuracy decrease with longer melodies or longer gaps? Use this to calibrate the difficulty of your daily ear training practice.", why: "Accuracy tracking across different difficulty levels shows you exactly where your melodic memory caps out. Maybe you're perfect at 3 notes but fall apart at 5. Maybe you're fine with no gap but struggle with the 10-second delay. The specific point where accuracy drops is where you should focus your practice — that's your growth edge." }
      ],
      feel: "When you nail a sing-back, it should feel like the melody is playing inside your head before your voice even starts. The voice just follows the internal playback. When you miss, it should feel like the melody is foggy or fragmented in your mind — pieces are there but the connections are unclear.",
      wrong: "If you can't hold even 3 notes in memory, the issue might be attention rather than memory. Make sure you're truly listening during the playback — not thinking about what to sing. Close your eyes, clear your mind, and let the melody enter your ear without any planning. Then trust that your memory received it.",
      sarah: "This is how Gene will learn songs by ear — and it is how his musical heroes learned. Jeff Buckley did not read sheet music for most of the covers he performed. He heard melodies, held them in his mind, and sang them back. That skill starts right here, with 3 little notes. Between attempts, wait a full 60 seconds before trying to sing the melody back. That delay makes the retrieval harder — and the harder the retrieval, the stronger the memory trace it builds.",
      levelUp: "Accurately sing back 5-note melodies after a single hearing, and name at least 3 of the 4 intervals correctly."
    },
    {
      id: "v5e8", time: 3, title: "Chord Quality: Major, Minor, and Seventh by Ear", type: "vocal",
      what: "Learn to identify chord quality by ear — is it major, minor, or a dominant 7th? — and sing the defining interval. This trains the harmonic perception that lets you hear the emotional color of music in real time.",
      setup: "Guitar in hand. Strum various chord types. Pitch Detector on.",
      referencePitches: getPitchRange("C3", "C4"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      recorder: true,
      steps: [
        { text: "Strum C major. Listen for 5 seconds. Now strum C minor (move the E string down one fret to Eb). Listen for 5 seconds. Alternate between them. The major is bright, open, resolved. The minor is dark, deep, yearning. Feel the difference in your body, not just your ears.", why: "The major/minor distinction is the most fundamental chord quality in Western music, and it's determined by a single note — the 3rd. C major has E natural (major 3rd); C minor has Eb (minor 3rd). One half-step changes the entire emotional character of the chord. Training your body to feel this difference (not just intellectually know it) is essential because in real musical situations, you don't have time to analyze — you have to feel." },
        { text: "Strum C major and sing the major 3rd (E). Then strum C minor and sing the minor 3rd (Eb). The half-step difference between E and Eb is tiny, but your voice and your ear need to distinguish them instantly.", why: "Singing the defining interval of each chord quality anchors the distinction in your voice — not just your ear. The motor act of singing E versus Eb creates a physical memory that complements the auditory memory. Over time, hearing a major chord will automatically trigger the sensation of the major 3rd in your throat, and vice versa. This multimodal encoding (ear + voice + body) is much more robust than ear-only training." },
        { text: "Now strum a dominant 7th chord: C7 (C-E-G-Bb). It sounds like C major with an added tension — a note that wants to resolve. Find the 7th (Bb) and sing it. The 7th is the 'blues note' — it adds grit and soul.", why: "The dominant 7th adds a note that creates harmonic tension. The Bb (flat 7th) wants to pull down to A, which would be the 3rd of an F chord — this is why C7 'wants' to resolve to F. Understanding this pull by hearing it (not just reading about it) is the foundation of understanding chord progressions. Blues, jazz, reggae, and soul all rely heavily on dominant 7th chords, making this quality essential for Gene's genres." },
        { text: "Close your eyes. Have someone strum (or strum without looking at your hand) one of the three chord types: major, minor, or 7th. Identify it by ear before looking. Do 10 rounds and track your accuracy.", why: "Blind identification tests genuine ear recognition rather than visual chord-shape recognition. When you see your hand forming a minor chord shape, your brain can identify 'minor' from visual cues alone. Removing the visual forces the ear to do the work independently. This is the real-world skill — when you hear a song on the radio, you can't see the guitarist's hands. Your ear has to identify the chord quality on its own." },
        { text: "For each chord you identify, immediately sing the 3rd (or 7th, for dominant chords). This proves you're not just guessing the label — you're hearing the specific note that defines the quality.", why: "Singing the defining interval is the gold standard for chord quality recognition. Anyone can learn to guess 'major' or 'minor' from the overall mood, but singing the specific note that creates that mood proves deep harmonic hearing. It's the difference between recognizing a color ('that's blue') and mixing the exact shade on a palette. The second skill leads to much more sophisticated musical abilities." },
        { text: "Expand your palette: strum a minor 7th chord (Am7 = A-C-E-G). This sounds like Am but with an added warmth. Compare to Am (darker, simpler) and A7 (brighter, tense). Four chord qualities to distinguish: major, minor, dominant 7th, minor 7th.", why: "Minor 7th chords are everywhere in the genres Gene loves — Khruangbin, soul, R&B, and jazz-influenced psych. The minor 7th has a sophisticated, warm quality that's neither as stark as a plain minor nor as tense as a dominant 7th. Adding it to your recognition palette lets you hear the harmonic language of soul and jazz, where minor 7ths are as common as basic major and minor chords are in pop and rock." },
        { text: "Listen to a song from Gene's playlist (Khruangbin, DOPE LEMON, Skinshape). Try to identify the chord quality of each chord as it passes. You don't need to name the root — just 'that was major,' 'that was minor,' 'that was a 7th.' How many can you identify in real time?", why: "Applying chord quality recognition to real music is the ultimate test and the ultimate purpose of the skill. Real songs move faster than exercises, the chords are dressed up with production, and the context keeps changing. If you can track chord qualities through an actual song — even partially — your ear training is translating to musical understanding. Every chord you identify correctly deepens your relationship with music you already love." }
      ],
      feel: "Major should feel bright and open — like stepping into sunlight. Minor should feel deep and contemplative — like looking at the ocean at dusk. Dominant 7th should feel tense and expectant — like the moment before a wave breaks. Minor 7th should feel warm and sophisticated — like a jazz club at midnight.",
      wrong: "If major and minor sound the same to you, isolate the 3rd: strum C major and pluck the B string (E). Then strum C minor and pluck the B string (Eb). Alternate between JUST those two notes. The half-step difference should become obvious. If it doesn't, you may need more practice with basic pitch discrimination from Level 3 before continuing.",
      sarah: "Gene, chord quality recognition is what lets you learn songs by ear efficiently. Instead of trying every chord until one fits, you'll hear 'that's a minor chord' and immediately narrow your options to minor chords. It cuts the guesswork in half — or more.",
      levelUp: "Correctly identify 8 out of 10 blind chord quality tests (major, minor, dominant 7th, minor 7th) and sing the defining interval of each."
    },
    {
      id: "v5e9", time: 3, title: "The Transcription Method: Learning Songs by Ear", type: "vocal",
      what: "A systematic approach to learning any song by ear. Instead of guessing and checking, you'll use a step-by-step method that builds on every skill in this level: chord quality identification, root tracking, interval recognition, and melodic dictation.",
      setup: "Phone with a song queued up (choose a simple one: Jack Johnson, Nick Drake, or any Gene favorite). Guitar in hand. Notebook or notes app for writing down what you hear.",
      recorder: true,
      referencePitches: getPitchRange("E3", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      steps: [
        { text: "Choose a simple song you love but haven't learned yet. Play the first 30 seconds three times. Don't try to figure anything out — just listen. Let the song wash over you. What do you notice? The mood? The tempo? The general direction of the melody?", why: "The first listen should be pure absorption. Neuroscience research on music perception shows that the brain processes music holistically before analytically — you perceive the overall mood, tempo, and energy before you can identify individual notes or chords. Trying to analyze on the first listen fights this natural processing order. Three full listens at the absorption stage gives your brain time to build a rich holistic representation that subsequent analysis can draw from." },
        { text: "Fourth listen: focus ONLY on the bass notes. Hum along with the lowest notes you can hear. These are the chord roots. Don't worry about the melody yet — the bass tells you the harmonic foundation.", why: "The bass line contains the harmonic roadmap of any song. Identifying roots first (before melody or chords) gives you the foundation that everything else is built on. This is the most efficient analysis order: roots tell you what key you're likely in, roots reveal the chord progression, and the chord progression contextualizes the melody. Professional transcribers almost always start with the bass." },
        { text: "Sing the bass notes you've identified. Check them on guitar — find each root on the low E or A string. Write down the root sequence. Even if you only get 2-3 roots, that's a start.", why: "Committing your bass-note hearing to paper (or a notes app) creates a working document you can refine. Most people can identify at least the first root and one or two chord changes on initial attempts. Writing them down prevents the frustrating experience of hearing something, forgetting it, and having to start over. Each pass adds more information to the document." },
        { text: "Fifth listen: for each root you've identified, determine the chord quality — is it major, minor, or a 7th? Use the skills from v5e8. Hum the 3rd of each chord to check your identification. Write the qualities next to the roots: 'Am - C - G - D' etc.", why: "Adding chord quality to the roots gives you the actual chords, not just the root sequence. This is where the chord quality training from v5e8 pays off directly. If you can hear that the first chord is A minor (not A major), you've identified the chord completely from ear alone — no guessing required. Each correct identification reinforces the ear training and builds confidence for harder songs." },
        { text: "Now focus on the melody. Listen to the verse melody 3 times. Hum it. Simplify it to the most important notes — where does it start, where does it go, where does it land? Sing the simplified version and check against the recording.", why: "Melody transcription is easier when you start with a simplified skeleton rather than trying to capture every ornament. The 'important notes' are usually the ones on strong beats and the ones at phrase endings — these are the structural notes that your brain automatically emphasizes in memory. Once you have the skeleton, adding ornamental notes and rhythmic details is much easier because you have a framework to hang them on." },
        { text: "Try to figure out the melody's relationship to the chords. On the first chord, does the melody start on the root? The 3rd? The 5th? This connects the melody to the harmony and makes both easier to remember.", why: "Understanding melody-harmony relationships is the deepest level of transcription. When you know that the melody starts on the 5th of Am (E) and moves to the root of C (C), you're not just memorizing pitches — you're understanding the musical architecture. This architectural understanding means you can transpose the song to any key, because you know the relationships rather than the absolute pitches." },
        { text: "Attempt to play and sing the first verse of the song using your transcription. How close is it? Where are the gaps? Go back to specific sections and listen again, filling in the gaps. Each pass should get you closer.", why: "Playing and singing your transcription is the final verification. Where it sounds right confirms your ear training is working. Where it sounds wrong identifies specific hearing gaps that need more listening passes. The iterative process — listen, attempt, compare, refine — is exactly how professional musicians learn songs by ear. It's not a talent; it's a method." },
        { text: "Document your transcription process: how many listens did it take? Which parts were easy to hear and which required multiple passes? What would you do differently next time? Each transcription builds the meta-skill of efficient ear-based learning.", why: "Reflecting on the process improves the process itself. You'll notice patterns: maybe chord roots come easily but melody is harder, or maybe you always struggle with the same type of chord change. These insights guide your practice priorities and make each subsequent transcription faster. Over time, songs that would have taken 30 minutes to figure out will take 5 minutes." }
      ],
      feel: "Transcription should feel like detective work — putting together clues to reconstruct a picture. It's deeply satisfying when the pieces click together and you can play the song. The first time you learn a song entirely by ear, it changes your relationship with music forever.",
      wrong: "If you're getting frustrated and nothing sounds right, the song might be too complex for your current level. Start with songs that have 3-4 chords and a simple melody: Jack Johnson's 'Banana Pancakes,' Nick Drake's 'Day is Done,' Bob Marley's 'Three Little Birds.' Complexity comes later; method comes first.",
      sarah: "This is one of the most empowering skills in music. Once Gene can learn songs by ear, he doesn't need tabs, chord charts, or YouTube tutorials. The music itself becomes the teacher. That's how his heroes learned — by listening, deeply and carefully, to the music they loved.",
      levelUp: "Successfully transcribe and perform the verse section of a simple song using only your ears — no tabs, no chord charts, no YouTube."
    },
    {
      id: "v5e10", time: 3, title: "Level 5 Integration: The Listening Musician", type: "vocal",
      what: "Combine every ear training skill from this level into an integrated musical exercise. Chord tone singing, interval production, melodic creation, bass line hearing, and chord quality recognition — all flowing together as real music-making, not isolated drills.",
      setup: "Guitar in hand. Choose a backing track. Pitch Detector on. Recorder ready.",
      recorder: true,
      pitchContour: true,
      referencePitches: getPitchRange("A2", "A3"),
      pianoKeys: { notes: ["A3", "C4", "D4", "E4", "G4"], label: "Chord Tones", range: ["A3", "G4"] },
      tracks: [{ name: "Khruangbin Style 80", src: "/khruangbin-style-80.mp3" }, { name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }, { name: "Desert Blues 75", src: "/desert-blues-75.mp3" }],
      steps: [
        { text: "Start the Khruangbin Style 80 backing track. Listen for 8 bars without singing. What key is it in? What chord quality do you hear? Can you feel the root? Don't analyze — just listen and let your ear tell you.", why: "Starting with pure listening activates your holistic music perception — the accumulated ear training from this entire level. Instead of approaching the track analytically (what are the chords?), you're letting your trained ear process it naturally. The answer should come as a feeling before it becomes a thought. If you trained v5e8 well, you'll feel 'minor' or 'major' before you can name the specific chord." },
        { text: "Bars 9-16: sing the root notes. Whatever you think the roots are, sing them on beat 1 of each bar. Low register, chest voice. This is your v5e5 bass line skill applied to unfamiliar music.", why: "Singing roots over an unfamiliar backing track tests real-time harmonic hearing. Unlike practicing over Am-C-G-D (where you know what's coming), this track might surprise you with unexpected chord changes. Your ear has to track the harmony in real time and your voice has to follow. This is the difference between practicing ear training and using ear training." },
        { text: "Bars 17-24: add the 3rd and 5th. Sing root on beat 1, 3rd on beat 2, 5th on beat 3. You're outlining the chord structure with your voice — your v5e1 and v5e2 skills in action.", why: "Arpeggiating chord tones over a backing track combines root tracking, chord quality identification, and interval production into a single musical gesture. If you can outline root-3rd-5th accurately over changing harmony, you're demonstrating a comprehensive understanding of what's happening harmonically in real time. This is how jazz singers navigate complex chord changes — they hear the chord, identify the tones, and sing them." },
        { text: "Bars 25-32: create a melody using chord tones and passing notes. Let it flow naturally — don't just arpeggate up and down. Shape it like a real melody with contour, rhythm, and phrasing. This is your v5e3 skill alive.", why: "The transition from arpeggiating chord tones to creating melodies is the transition from exercise to music. A melody has shape — it rises, falls, pauses, accelerates. It has phrasing — some notes are long, some are short. It has personality — it reflects the singer's taste and emotion. When you create a melody over unfamiliar harmony, you're improvising at a level that requires all of your ear training skills working together." },
        { text: "Bars 33-40: switch to singing in a different register. If you've been in the middle, go low (bass line territory). If you've been low, go to the top of your comfortable range. The ear training should work regardless of register.", why: "Register changes test whether your ear training is pitch-independent. If you can only hear and produce chord tones in one octave, the skill is incomplete. True harmonic hearing works in any register — you should be able to sing the 3rd of any chord whether you're in chest voice or head voice. Switching registers mid-performance proves this flexibility." },
        { text: "Switch to the Desert Blues 75 backing track for bars 41-56. Different feel, different harmonic language. Apply the same process: listen, find roots, outline chords, create a melody. How quickly can you adapt?", why: "Changing backing tracks tests the generalizability of your ear training. The Khruangbin track and the Desert Blues track have different harmonic flavors, tempos, and moods. If your ear training only works over one track, it's memorized responses rather than genuine skill. Adapting quickly to a new harmonic environment proves that you're hearing, not remembering." },
        { text: "Final 8 bars: close your eyes and sing a melody that responds to whatever you hear in the backing track. No planning, no analysis — just let your trained ear guide your voice. Record this section.", why: "Eyes-closed, intuitive singing is the endpoint of ear training. When analysis becomes automatic, it disappears — you're just hearing music and responding. The melody that comes out reflects everything you've trained: your intervals are accurate, your chord tones are solid, your phrasing has shape. But you're not thinking about any of those things. You're just singing. This is what Jeff Buckley sounded like — a musician whose ear training was so deep it became invisible." },
        { text: "Listen to the full recording, especially the final 8 bars. Retake the diagnostic from v5e0. Rate yourself again on: chord tone hearing (1-5), interval accuracy (1-5), root tracking (1-5), melodic improvisation (1-5). Compare to your initial scores.", why: "Closing the loop between the opening diagnostic and this integration exercise gives you concrete evidence of growth. The numbers may or may not have changed dramatically — ear training progress is often slow — but the qualitative experience should feel different. You should be more confident, more accurate, and more musical in your responses. The comparison motivates continued practice." }
      ],
      feel: "This should feel like making music, not doing exercises. All the individual skills from this level should blend together into a fluid, musical experience. When it's working, you'll forget you're 'training' and just be playing with the music.",
      wrong: "If it still feels like a series of isolated exercises, you need more practice on the individual skills before integration. The integration works when the component skills are automatic enough to blend. If you're still consciously thinking 'find the root... now the 3rd... now the 5th,' stay with the individual exercises for another week before attempting this integration.",
      sarah: "Gene, this is the exercise where you realize that ear training is not a separate skill — it IS musicianship. Everything you have learned in this level — hearing chord tones, singing intervals, tracking harmony, creating melodies — is what musicians do when they play. You are not learning about music; you are learning to BE a musician. In your final two minutes, mix the ear work with something from a different level — a dynamic arc from L7, a rhythmic phrase from L4. That interleaving is where the deepest integration happens. End on whatever moment felt most like real music-making.",
      levelUp: "A 2-minute free-form vocal improvisation over an unfamiliar backing track that demonstrates accurate chord tone singing, smooth melodic contour, and confident harmonic navigation — without any planning or analysis."
    },
    {
      id: "v5e11", time: 3, title: "Generation Check — Chord Tones from Silence", type: "vocal",
      what: "From complete silence, with no external reference, can you generate the chord tones of C major and Am? This tests whether harmonic relationships have been internalized deeply enough to produce from pure internal hearing.",
      setup: "Pitch Detector on. No drone. No guitar. Complete silence.",
      referencePitches: getPitchRange("A2", "E4"),
      pitchContour: true,
      steps: [
        { text: "Complete silence. Close your eyes. Imagine a C major chord — feel its bright, open quality. Now from that internal hearing, sing the root (C). Check with pitch detector. Then the 3rd (E). Then the 5th (G). Each note found from the imagined chord, not from a played reference.", why: "Generating chord tones from an imagined harmonic context tests whether you've internalized harmonic relationships — not just individual pitches, but the notes that BELONG to a chord. This is the musical equivalent of spelling a word from memory rather than copying it." },
        { text: "Now imagine Am — feel the shift to something darker, more intimate. From that internal hearing, sing A, then C, then E. Check each. The same notes (C and E) appear in both chords — but they feel different in each harmonic context. C in C major is the root (stable, grounded). C in Am is the minor 3rd (aching, emotional).", why: "Context-dependent note quality is the foundation of harmonic hearing. The same pitch carries different emotional and functional weight depending on the chord. Generating notes from imagined harmonic contexts builds functional hearing — you're not just audiating pitches but audiating their role within a harmony." },
        { text: "Final test: alternate imagined chords. Hear C major → sing its 5th (G). Hear Am → sing its 5th (E). Hear C major → sing its 3rd (E). Hear Am → sing its 3rd (C). Rapid context switching from silence tests how fluidly you can shift between harmonic worlds in your internal hearing.", why: "Rapid harmonic context switching is what happens in real time when you listen to a chord progression. Each chord creates a new context that redefines every note's function. Building this skill from silence means you're developing the internal harmonic awareness that lets musicians 'hear' a progression before it happens." }
      ],
      feel: "This should feel like finding music inside silence — reaching into your internal harmonic memory and pulling out specific notes by their function within a chord.",
      wrong: "If you can't generate notes from imagined chords, that's diagnostic: you need more time with the chord-tone singing exercises (v5e1, v5e3). Generation from silence is a milestone checkpoint, not a requirement for moving forward.",
      sarah: "Gene, this is where all the ear training comes together. If you can hear a chord in your head and sing any note from it — that's the skill that lets you improvise over changes, write harmony parts, and hear what a song needs before you play it."
    },
    {
      id: "v5e12", time: 5, title: "The Silent Exercise — Mental Rehearsal", type: "listen",
      what: "Choose any exercise from Level 3. Don't sing it — run it entirely in your imagination. Hear every note, feel every body location, sense every emotional shift. Research shows mental rehearsal activates nearly the same neural pathways as physical practice.",
      setup: "Nothing. Sit comfortably. Eyes closed. Pick a Level 3 exercise you've completed.",
      steps: [
        { text: "Choose a Level 3 exercise you know well (v3e1 Forward Model, v3e4 Silent Scale, or v3e14 Silence Ladder are good choices). Read through its steps to refresh your memory. Now set everything down. Close your eyes.", why: "Mental rehearsal works best on material you've already practiced physically. The neural pathways exist — you're strengthening them through imagination." },
        { text: "Run the entire exercise in your imagination at real tempo. Hear every note vividly. Feel every body location — chest warmth for low notes, mask brightness for high ones. Sense every emotional shift. Don't make any sound. Don't move your hands. Just live the exercise silently inside.", why: "Aarhus University 2021 found that imagined singing activates nearly the same neural real estate as actual singing. Silent rehearsal is not a lesser form of practice — it IS practice. It produces equivalent learning gains in approximately one-third the time of physical practice." },
        { text: "Rate your vividness 1-5. 1 = couldn't hold any notes internally. 3 = heard some, lost others. 5 = the exercise played in your head as vividly as doing it aloud. Your rating IS your audiation development score.", why: "Self-assessment of imagery vividness is the most practical measure of audiation strength. The gap between physical ability and mental vividness is your audiation gap — it closes with practice." },
        { text: "If below 3: do the exercise aloud, then try the silent version again. Physical practice refreshes the neural trace; mental practice strengthens it. Compare your two ratings.", why: "Physical-then-mental sequencing is the most efficient way to build audiation. The physical practice lays down the neural representation; the mental practice reinforces it without fatigue." }
      ],
      feel: "This should feel deeply meditative — dreaming music with your eyes closed. The room is silent but your internal experience is rich with pitch, body sensation, and emotion.",
      wrong: "If you catch yourself humming or moving, gently stop. The exercise is purely internal. If you can't hold any musical content mentally, that's not failure — more physical practice is needed first.",
      sarah: "Gene, this is practice you can do anywhere — before sleep, waiting in line, on a road trip. Musicians who combine physical and mental rehearsal improve faster than those who only practice physically. Your inner ear gets stronger even when no one can hear it working."
    },
    {
      id: "v5e13", time: 5, title: "Groove Seed and Silence", type: "vocal",
      what: "A backing track plays a familiar groove. It fades to silence. Can you hold the music alive inside — the feel, the harmonic color, the rhythmic character — and stay in the pocket? This is audiation applied to a complete musical context.",
      setup: "Backing track. Guitar optional.",
      tracks: [{ name: "Reggae One Drop 85", src: "/reggae-one-drop-85.mp3" }, { name: "Groove Beat 90", src: "/groove-beat-90.mp3" }, { name: "Deep Soul Groove 80", src: "/deep-soul-groove-80.mp3" }],
      referencePitches: getPitchRange("A2", "A3"),
      recorder: true,
      steps: [
        { text: "Choose a backing track. Play it for 1 minute — strum along, hum or sing, let the groove saturate your body. Feel where the pulse lives: foot, chest, head-nod.", why: "Familiarity is key. The more deeply the groove lives in your body, the more vividly you can hold it in silence. The earworm mechanism (J. Neuroscience 2021) works because repeated exposure encodes the groove into involuntary musical imagery." },
        { text: "Track plays 8 bars. Pause. Sing through 4 bars of silence — maintain not just the tempo but the FEEL. The reggae lilt, the soul groove swing, the bass pattern weight. Resume. Still in the pocket?", why: "Holding groove in silence is harder than holding tempo because groove has swing, emphasis, and emotional color beyond bare pulse. The auditory cortex activates during silent gaps in familiar music — the brain literally continues playing internally." },
        { text: "Track plays 4 bars, silence for 8 bars. You're in silence longer than you had reference. Let the groove live in your foot, your breathing, your internal hearing. Resume. Check.", why: "Longer silence forces genuine internal generation past echoic groove memory. Your somatic anchors (foot, breath) become the primary timekeepers." },
        { text: "Minimal seed: track plays 2 bars, silence for 8 bars. Can you sustain 4x the input length?", why: "This tests whether 2 bars is enough to fully activate the internal groove representation. It mirrors the pitch audiation sequence: full reference → brief reference → generation from memory." },
        { text: "Free exploration: track plays 2 bars, then you improvise a vocal melody over silence for as long as the groove stays alive inside you. When it fades, restart the track. How many bars can you sustain? That number is your groove audiation endurance — it grows with practice.", why: "Simultaneous melody generation and groove maintenance from internal hearing is the capstone. You're running two audiation streams (pitch + rhythm) from a single brief seed." }
      ],
      feel: "The silence should feel like the music went underwater — muffled but still alive, held in your body. When the track returns and you're still in the pocket, the groove never stopped inside you.",
      wrong: "If you consistently lose the feel during silence, the groove isn't deeply enough absorbed yet. Spend more focused listening time with the backing track before attempting seed-and-silence.",
      sarah: "Gene, this bridges everything — pitch audiation, rhythm audiation, and groove feel, all held in silence from a brief seed. The musicians you love never lose the groove inside them. You're building that same internal continuity."
    }
  ]
};